import{_ as n,o as t,c as i,a0 as a}from"./chunks/framework.jwovEGr5.js";const s=JSON.parse('{"title":"CRM","description":"","frontmatter":{"title":"CRM"},"headers":[],"relativePath":"crm.md","filePath":"crm.md"}'),c={name:"crm.md"};function e(o,h,l,r,g,d){return t(),i("div",null,[...h[0]||(h[0]=[a('<h1 id="crm-quan-ly-quan-he-khach-hang" tabindex="-1">CRM (Quản lý Quan hệ Khách hàng) <a class="header-anchor" href="#crm-quan-ly-quan-he-khach-hang" aria-label="Permalink to &quot;CRM (Quản lý Quan hệ Khách hàng)&quot;">​</a></h1><h2 id="tong-quan" tabindex="-1">Tổng quan <a class="header-anchor" href="#tong-quan" aria-label="Permalink to &quot;Tổng quan&quot;">​</a></h2><p>Mô-đun CRM trong ABNERP giúp doanh nghiệp quản lý toàn bộ vòng đời của khách hàng — từ khi là khách hàng tiềm năng cho đến khi trở thành khách hàng trung thành. Hệ thống cung cấp các công cụ để theo dõi tương tác, quản lý cơ hội bán hàng và triển khai chiến dịch marketing hiệu quả.</p><h2 id="quy-trinh-crm" tabindex="-1">Quy trình CRM <a class="header-anchor" href="#quy-trinh-crm" aria-label="Permalink to &quot;Quy trình CRM&quot;">​</a></h2><p>Quy trình CRM tiêu chuẩn trong ABNERP bao gồm các bước sau:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Khách hàng tiềm năng (Lead) → Cơ hội (Opportunity) → Khách hàng (Customer)</span></span></code></pre></div><h3 id="_1-khach-hang-tiem-nang-lead" tabindex="-1">1. Khách hàng tiềm năng (Lead) <a class="header-anchor" href="#_1-khach-hang-tiem-nang-lead" aria-label="Permalink to &quot;1. Khách hàng tiềm năng (Lead)&quot;">​</a></h3><p>Lead là những cá nhân hoặc tổ chức có khả năng quan tâm đến sản phẩm/dịch vụ của bạn.</p><p><strong>Nguồn Lead phổ biến:</strong></p><ul><li>Website: Form đăng ký tư vấn, yêu cầu báo giá</li><li>Sự kiện: Hội chợ, triển lãm, hội thảo</li><li>Marketing: Quảng cáo, email marketing, mạng xã hội</li><li>Giới thiệu: Khách hàng cũ giới thiệu</li><li>Nhập liệu thủ công từ danh sách khách hàng tiềm năng</li></ul><p><strong>Thông tin Lead:</strong></p><ul><li>Họ tên người liên hệ, công ty, chức vụ</li><li>Email, số điện thoại, địa chỉ</li><li>Nguồn gốc</li><li>Ghi chú về nhu cầu và sở thích</li></ul><h3 id="_2-co-hoi-opportunity" tabindex="-1">2. Cơ hội (Opportunity) <a class="header-anchor" href="#_2-co-hoi-opportunity" aria-label="Permalink to &quot;2. Cơ hội (Opportunity)&quot;">​</a></h3><p>Khi lead đã được đánh giá có nhu cầu thực sự, bạn chuyển lead thành cơ hội.</p><p><strong>Các giai đoạn của cơ hội:</strong></p><table tabindex="0"><thead><tr><th>Giai đoạn</th><th>Mô tả</th></tr></thead><tbody><tr><td>Tiếp cận</td><td>Liên hệ khách hàng lần đầu</td></tr><tr><td>Tư vấn</td><td>Tìm hiểu nhu cầu, giới thiệu giải pháp</td></tr><tr><td>Báo giá</td><td>Gửi báo giá, thương thảo điều khoản</td></tr><tr><td>Đàm phán</td><td>Thương lượng giá cả, hợp đồng</td></tr><tr><td>Chốt deal</td><td>Ký hợp đồng và bắt đầu triển khai</td></tr></tbody></table><p><strong>Quản lý cơ hội với các tính năng:</strong></p><ul><li>Giá trị cơ hội dự kiến</li><li>Xác suất chốt thành công (%)</li><li>Ngày dự kiến chốt</li><li>Đối thủ cạnh tranh (nếu có)</li><li>Lịch sử tương tác với khách hàng</li></ul><h3 id="_3-khach-hang-customer" tabindex="-1">3. Khách hàng (Customer) <a class="header-anchor" href="#_3-khach-hang-customer" aria-label="Permalink to &quot;3. Khách hàng (Customer)&quot;">​</a></h3><p>Khi cơ hội được chốt thành công, thông tin sẽ được chuyển thành khách hàng chính thức.</p><p><strong>Sau khi tạo khách hàng, bạn có thể:</strong></p><ul><li>Tạo đơn bán hàng, hóa đơn</li><li>Quản lý công nợ phải thu</li><li>Theo dõi lịch sử giao dịch</li><li>Thiết lập giới hạn tín dụng</li><li>Gửi email marketing và thông báo</li></ul><h2 id="cac-tinh-nang-chinh" tabindex="-1">Các tính năng chính <a class="header-anchor" href="#cac-tinh-nang-chinh" aria-label="Permalink to &quot;Các tính năng chính&quot;">​</a></h2><h3 id="chien-dich-campaign" tabindex="-1">Chiến dịch (Campaign) <a class="header-anchor" href="#chien-dich-campaign" aria-label="Permalink to &quot;Chiến dịch (Campaign)&quot;">​</a></h3><p>Cho phép tạo và theo dõi các chiến dịch marketing:</p><table tabindex="0"><thead><tr><th>Loại chiến dịch</th><th>Mô tả</th></tr></thead><tbody><tr><td>Email marketing</td><td>Gửi email hàng loạt đến khách hàng</td></tr><tr><td>Quảng cáo trả phí</td><td>Google Ads, Facebook Ads, TikTok Ads</td></tr><tr><td>Sự kiện</td><td>Hội thảo, webinar, roadshow</td></tr><tr><td>Nội dung</td><td>Blog, video, podcast</td></tr></tbody></table><p>Mỗi chiến dịch có thể theo dõi:</p><ul><li>Ngân sách và chi phí thực tế</li><li>Số lượng lead thu được</li><li>Tỷ lệ chuyển đổi (ROI)</li><li>Hiệu quả từng kênh</li></ul><h3 id="khach-hang-tiem-nang-prospect" tabindex="-1">Khách hàng tiềm năng (Prospect) <a class="header-anchor" href="#khach-hang-tiem-nang-prospect" aria-label="Permalink to &quot;Khách hàng tiềm năng (Prospect)&quot;">​</a></h3><p>Prospect là lead đã được xác minh thông tin và có nhu cầu nhưng chưa sẵn sàng mua ngay. Đây là giai đoạn trung gian giữa lead và opportunity.</p><h3 id="bao-cao-crm" tabindex="-1">Báo cáo CRM <a class="header-anchor" href="#bao-cao-crm" aria-label="Permalink to &quot;Báo cáo CRM&quot;">​</a></h3><p>ABNERP cung cấp các báo cáo CRM thiết yếu:</p><ul><li><strong>Báo cáo Lead theo nguồn</strong>: Lead đến từ đâu nhiều nhất?</li><li><strong>Báo cáo cơ hội theo nhân viên</strong>: Ai đang chốt deal nhiều nhất?</li><li><strong>Báo cáo doanh thu dự kiến</strong>: Tổng giá trị cơ hội đang mở</li><li><strong>Tỷ lệ chốt deal</strong>: Bao nhiêu % cơ hội thành công?</li><li><strong>Thời gian chốt deal trung bình</strong>: Vòng đời bán hàng dài bao lâu?</li></ul><h2 id="tich-hop" tabindex="-1">Tích hợp <a class="header-anchor" href="#tich-hop" aria-label="Permalink to &quot;Tích hợp&quot;">​</a></h2><p>Mô-đun CRM liên kết chặt chẽ với các mô-đun khác:</p><ul><li><strong>Bán hàng</strong>: Cơ hội thành công tự động tạo đơn bán hàng</li><li><strong>Kế toán</strong>: Khách hàng có công nợ và lịch sử thanh toán</li><li><strong>Marketing</strong>: Chiến dịch đồng bộ với lead và cơ hội</li><li><strong>Dịch vụ</strong>: Quản lý yêu cầu hỗ trợ sau bán hàng</li></ul><h2 id="video-huong-dan" tabindex="-1">Video hướng dẫn <a class="header-anchor" href="#video-huong-dan" aria-label="Permalink to &quot;Video hướng dẫn&quot;">​</a></h2><ul><li><a href="https://www.youtube.com/watch?v=example9" target="_blank" rel="noreferrer">Quy trình CRM trên ABNERP</a></li><li><a href="https://www.youtube.com/watch?v=example10" target="_blank" rel="noreferrer">Quản lý Lead và Cơ hội</a></li><li><a href="https://www.youtube.com/watch?v=example11" target="_blank" rel="noreferrer">Tạo và theo dõi chiến dịch marketing</a></li></ul>',38)])])}const p=n(c,[["render",e]]);export{s as __pageData,p as default};
